body.script:
// Wire any [data-mh-consent-open] element to ask  to
// open the right modal for the visitor's jurisdiction. Delegated so a
// single listener covers every consent trigger on the page (currently
// just the footer link, but future surfaces are free).
document.addEventListener('click', function (e) {
  var t = e.target;
  if (!(t instanceof Element)) return;
  if (!t.closest('[data-mh-consent-open]')) return;
  e.preventDefault();
  window.dispatchEvent(new CustomEvent('mh:consent:open'));
});

// ConsentBanner controller — runs once on every page load.
//
// Responsibilities:
//   1. Mirror localStorage `mh-consent` into a same-name cookie so the
//      Worker can read it on the next request. Runs synchronously
//      before AnalyticsBeacon emits — its fetch will pick up the
//      cookie this script just wrote.
//   2. Show the first-visit banner if (a) we're in an opt-in
//      jurisdiction and (b) no stored choice exists.
//   3. Wire up the Manage-preferences modal and (US-only) opt-out
//      modal so they can be opened later by the footer link via the
//      `mh:consent:open` custom event.
(function () {
  var root = document.getElementById('mh-consent-root');
  if (!root) return;
  var STORAGE_KEY = root.dataset.storageKey || 'mh-consent';
  var COOKIE_MAX_AGE = parseInt(root.dataset.cookieMaxAge || '0', 10) || 60 * 60 * 24 * 365;
  var optIn = root.dataset.optIn === '1';

  function readState() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (!raw) return null;
      var p = JSON.parse(raw);
      if (!p || typeof p !== 'object') return null;
      return {
        analytics: p.analytics === true,
        marketing: p.marketing === true,
        decidedAt: typeof p.decidedAt === 'number' ? p.decidedAt : null,
        optedOut: p.optedOut === true,
      };
    } catch (e) {
      return null;
    }
  }

  // Convert state → server-readable cookie value.
  function cookieFor(state) {
    if (!state) return 'none';
    if (state.optedOut) return 'optout';
    if (state.analytics && state.marketing) return 'full';
    if (state.analytics) return 'analytics';
    return 'rejected';
  }

  function writeCookie(value) {
    var parts = [
      STORAGE_KEY + '=' + encodeURIComponent(value),
      'Path=/',
      'Max-Age=' + COOKIE_MAX_AGE,
      'SameSite=Lax',
    ];
    if (location.protocol === 'https:') parts.push('Secure');
    document.cookie = parts.join('; ');
  }

  function persist(state) {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
    } catch (e) {
      // Quota / private mode — fall back to cookie-only.
    }
    writeCookie(cookieFor(state));
  }

  // ────────────────────────────────────────────────────────────
  // 1. Mirror existing state into cookie so the next /api/track
  //    (and the next pageview) sees it.
  var current = readState();
  writeCookie(cookieFor(current));

  // ────────────────────────────────────────────────────────────
  // 2. UI helpers
  var banner = root.querySelector('.mh-banner');
  var prefsModal = root.querySelector('[data-modal="prefs"]');
  var optoutModal = root.querySelector('[data-modal="optout"]');
  var toast = root.querySelector('.mh-toast');
  var lastFocused = null;

  function show(el) {
    if (!el) return;
    el.hidden = false;
    root.hidden = false;
  }
  function hide(el) {
    if (!el) return;
    el.hidden = true;
  }
  function showToast(text) {
    if (!toast) return;
    toast.textContent = text;
    toast.hidden = false;
    setTimeout(function () { toast.hidden = true; }, 2500);
  }

  function openPrefs() {
    if (!prefsModal) return;
    lastFocused = document.activeElement;
    // Dismiss the first-visit banner if it's still showing — the modal
    // is a strictly-more-detailed surface for the same choice.
    hide(banner);
    // Pre-fill toggles from current state.
    var s = readState();
    prefsModal.querySelectorAll('.mh-toggle').forEach(function (t) {
      var cat = t.getAttribute('data-category');
      var cb = t.querySelector('input');
      if (!cb || cb.disabled) return;
      if (cat === 'analytics') cb.checked = !!(s && s.analytics);
      if (cat === 'marketing') cb.checked = !!(s && s.marketing);
    });
    show(prefsModal);
    var firstBtn = prefsModal.querySelector('button.mh-btn-primary');
    if (firstBtn) firstBtn.focus();
  }
  function closePrefs() {
    hide(prefsModal);
    if (lastFocused && typeof lastFocused.focus === 'function') lastFocused.focus();
  }

  function openOptOut() {
    if (!optoutModal) return;
    lastFocused = document.activeElement;
    hide(banner); // belt-and-suspenders; banner shouldn't render in opt-out countries anyway
    show(optoutModal);
    var btn = optoutModal.querySelector('button.mh-btn-primary');
    if (btn) btn.focus();
  }
  function closeOptOut() {
    hide(optoutModal);
    if (lastFocused && typeof lastFocused.focus === 'function') lastFocused.focus();
  }

  // ────────────────────────────────────────────────────────────
  // 3. Decide whether to show the first-visit banner.
  if (optIn && !current) {
    show(banner);
  }

  // ────────────────────────────────────────────────────────────
  // 4. Button wiring (delegated)
  root.addEventListener('click', function (ev) {
    var t = ev.target;
    if (!(t instanceof Element)) return;
    var actionEl = t.closest('[data-action]');
    if (!actionEl) return;
    var action = actionEl.getAttribute('data-action');

    // Banner / modal close-on-backdrop both use data-action="cancel".
    if (action === 'cancel') {
      if (prefsModal && !prefsModal.hidden) closePrefs();
      if (optoutModal && !optoutModal.hidden) closeOptOut();
      return;
    }
    if (action === 'manage') {
      hide(banner);
      openPrefs();
      return;
    }
    if (action === 'accept') {
      persist({ analytics: true, marketing: true, decidedAt: Date.now() });
      hide(banner);
      showToast('Preferences saved');
      // Reload so the next render reflects identified mode server-side.
      setTimeout(function () { location.reload(); }, 250);
      return;
    }
    if (action === 'reject') {
      persist({ analytics: false, marketing: false, decidedAt: Date.now() });
      hide(banner);
      showToast('Preferences saved');
      setTimeout(function () { location.reload(); }, 250);
      return;
    }
    if (action === 'save') {
      var analytics = !!prefsModal.querySelector('.mh-toggle[data-category="analytics"] input').checked;
      var marketing = !!prefsModal.querySelector('.mh-toggle[data-category="marketing"] input').checked;
      persist({ analytics: analytics, marketing: marketing, decidedAt: Date.now() });
      closePrefs();
      showToast('Preferences saved');
      setTimeout(function () { location.reload(); }, 250);
      return;
    }
    if (action === 'optout') {
      persist({ analytics: true, marketing: false, optedOut: true, decidedAt: Date.now() });
      closeOptOut();
      showToast(root.dataset.optoutToast || 'Opted out.');
      setTimeout(function () { location.reload(); }, 250);
      return;
    }
  });

  // ────────────────────────────────────────────────────────────
  // 5. Footer link dispatches `mh:consent:open` — we listen and open
  //    the modal appropriate for the visitor's jurisdiction.
  window.addEventListener('mh:consent:open', function () {
    if (optIn) openPrefs();
    else openOptOut();
  });

  // Escape closes any open modal.
  document.addEventListener('keydown', function (e) {
    if (e.key === 'Escape') {
      if (prefsModal && !prefsModal.hidden) closePrefs();
      else if (optoutModal && !optoutModal.hidden) closeOptOut();
    }
  });
})();

(function () {
  var ENDPOINT = '/api/track';
  // For $pageleave: when this page view started, and whether we've already
  // sent its leave event (so visibilitychange + pagehide don't double-fire).
  var pageStart = Date.now();
  var leftSent = false;

  function emit(name, props) {
    if (typeof name !== 'string' || name.length === 0) return;
    try {
      var payload = {
        event: name,
        url: location.href,
        path: location.pathname,
        referrer: document.referrer || undefined,
      };
      if (props && typeof props === 'object') payload.props = props;
      // `keepalive: true` lets the POST finish even if the page is
      // unloading (link clicks, navigation). 64 KB body cap is way
      // more than we need.
      fetch(ENDPOINT, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
        keepalive: true,
        credentials: 'same-origin',
      }).catch(function () {
        /* swallow — analytics never breaks the page */
      });
    } catch (e) {
      /* swallow */
    }
  }

  // $pageleave — bounds session duration in PostHog. Uses navigator.sendBeacon
  // (fire-and-forget, survives unload without blocking it); falls back to a
  // keepalive fetch. Fired once per page view; the guard stops the
  // visibilitychange + pagehide pair from double-counting the same exit.
  function emitLeave() {
    if (leftSent) return;
    leftSent = true;
    try {
      var body = JSON.stringify({
        event: 'pageleave',
        url: location.href,
        path: location.pathname,
        referrer: document.referrer || undefined,
        props: { duration_ms: Date.now() - pageStart },
      });
      if (navigator.sendBeacon) {
        var blob = new Blob([body], { type: 'application/json' });
        if (navigator.sendBeacon(ENDPOINT, blob)) return;
      }
      fetch(ENDPOINT, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: body,
        keepalive: true,
        credentials: 'same-origin',
      }).catch(function () {});
    } catch (e) {
      /* swallow */
    }
  }

  // Initial pageview.
  emit('pageview');

  // Page exit. visibilitychange→hidden is the reliable signal (esp. mobile,
  // where pagehide/unload often don't fire); pagehide complements it for
  // desktop close / cross-document nav. The guard dedupes the pair.
  document.addEventListener('visibilitychange', function () {
    if (document.visibilityState === 'hidden') emitLeave();
  });
  window.addEventListener('pagehide', emitLeave);

  // Astro view-transition swaps replace the DOM without a full reload.
  // Close out the leaving page (so its dwell + session bound are recorded),
  // then start a fresh page view on the incoming one.
  document.addEventListener('astro:before-swap', emitLeave);
  document.addEventListener('astro:after-swap', function () {
    leftSent = false;
    pageStart = Date.now();
    emit('pageview');
  });

  // Auto-instrument CTA clicks. Fires `website_cta_click` on:
  //   - any element with [data-mh-event] (explicit instrumentation; the
  //     attribute value, if present, overrides the event name)
  //   - any  or  whose class contains the token "btn"
  //     (covers .btn / .btn-primary / .btn-secondary / .btn-on-accent /
  //     .btn-link site-wide — the marketing CTA convention)
  //
  // We deliberately do NOT auto-fire for plain header / footer nav
  // links — those navigations show up as the resulting pageview.
  function matchesCta(el) {
    if (!el || el.nodeType !== 1) return null;
    if (el.hasAttribute('data-mh-event')) return el;
    var tag = el.tagName;
    if (tag !== 'A' && tag !== 'BUTTON') return null;
    // className may be SVGAnimatedString on inline SVG roots; coerce.
    var cls = typeof el.className === 'string' ? el.className : (el.className && el.className.baseVal) || '';
    if (cls.split(/\s+/).indexOf('btn') !== -1) return el;
    // Common modifier classes — match any class starting with "btn-".
    if (cls.split(/\s+/).some(function (c) { return c.indexOf('btn-') === 0; })) return el;
    return null;
  }

  function gatherProps(el) {
    var props = {};
    var label = (el.textContent || '').trim().replace(/\s+/g, ' ').slice(0, 80);
    if (label) props.label = label;
    if (el.tagName === 'A') {
      var href = el.getAttribute('href');
      if (href) props.href = href.slice(0, 200);
    }
    // Any data-mh-* attributes beyond data-mh-event become props.
    for (var i = 0; i < el.attributes.length; i++) {
      var attr = el.attributes[i];
      if (attr.name.indexOf('data-mh-') === 0 && attr.name !== 'data-mh-event') {
        var key = attr.name.slice('data-mh-'.length);
        if (key && attr.value) props[key] = attr.value.slice(0, 200);
      }
    }
    return props;
  }

  document.addEventListener('click', function (ev) {
    var path = typeof ev.composedPath === 'function' ? ev.composedPath() : [];
    var cta = null;
    for (var i = 0; i < path.length; i++) {
      cta = matchesCta(path[i]);
      if (cta) break;
    }
    // Fallback for environments without composedPath() — walk up from target.
    if (!cta) {
      var t = ev.target;
      while (t && t !== document.body) {
        cta = matchesCta(t);
        if (cta) break;
        t = t.parentNode;
      }
    }
    if (!cta) return;
    var name = cta.getAttribute('data-mh-event') || 'website_cta_click';
    emit(name, gatherProps(cta));
  }, true); // capture phase so we see the click even if nested handlers stopPropagation

  // Public hook for page-level code — call with any event name from the
  // `EventName` union in src/lib/analytics/types.ts.  Today the schema
  // accepts only `pageview` and `website_cta_click`, both auto-emitted;
  // this hook is here for explicit future events (always `website_`-
  // prefixed by convention).
  window.__mh_track = emit;
})();
